const READ        = "r"
const WRITE       = "w"
const APPEND      = "a"
const READ_WRITE  = "r+"
const WRITE_READ  = "w+"
const APPEND_READ = "a+"

class File()
    var _handle: &u8
    var _open: bool

    fun open(path: u8[], mode: u8[]): bool
        _handle = _fopen(path, mode)
        _open = _ptr_valid(_handle)
        return _open

    fun close()
        if _open
            _fclose(_handle)
            _open = false

    @inline
    fun is_open(): bool
        return _open

    fun read_bytes(buf: u8[]): u32
        return _fread(buf, _handle)

